UPDATE lessons
SET
  title = 'Les cas ne changent pas les mots. Ils changent leur rôle.',
  content_blocks = '[{"type":"paragraph","text":"Pourquoi le mot школа devient-il parfois школе, школу ou школой ? Est-ce que ce sont plusieurs mots — ou le même mot qui joue plusieurs rôles ?"},{"type":"paragraph","text":"Imagine une pièce de théâtre : un acteur peut être le héros, le médecin, le professeur ou le voisin. L''acteur ne change pas. Seul son rôle change. En russe, c''est exactement la même chose : le mot reste le même, sa terminaison change parce que son rôle dans la phrase change."},{"type":"example","russian":"Шко́ла большая.","translation":"L''école est grande.","words":[{"text":"Шко́ла","role":"subject"}],"note":"Ici, школа est ce dont on parle — c''est le sujet. C''est la forme du dictionnaire."},{"type":"example","russian":"Я иду в шко́лу.","translation":"Je vais à l''école.","words":[{"text":"Я","role":"subject"},{"text":"иду","role":null},{"text":"в","role":null},{"text":"шко́лу","role":"place"}],"note":"Ici, школу est la destination — on se déplace vers l''école. La terminaison change."},{"type":"example","russian":"Я учусь в шко́ле.","translation":"J''étudie à l''école.","words":[{"text":"Я","role":"subject"},{"text":"учусь","role":null},{"text":"в","role":null},{"text":"шко́ле","role":"place"}],"note":"Ici, школе indique le lieu où l''on se trouve déjà — pas de mouvement, une position."},{"type":"paragraph","text":"Tu as déjà vu ce principe dans tes lectures Rossiyani : Louis va à l''université, puis se retrouve dans la salle de cours. Même université, deux fonctions différentes."},{"type":"example","russian":"— Ты идёшь в университе́т?","translation":"Tu vas à l''université ?","words":[{"text":"Ты","role":"subject"},{"text":"идёшь","role":null},{"text":"в","role":null},{"text":"университе́т","role":"place"}],"note":"Dans « Первый день в университете », cette phrase marque un mouvement vers l''université — la terminaison suit la direction.","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":4}},{"type":"example","russian":"В аудито́рии уже́ есть студе́нты.","translation":"Dans la salle, il y a déjà des étudiants.","words":[{"text":"В","role":null},{"text":"аудито́рии","role":"place"},{"text":"уже́","role":null},{"text":"есть","role":null},{"text":"студе́нты","role":"subject"}],"note":"Quelques phrases plus loin, « в аудитории » indique un lieu fixe — les étudiants sont déjà là. Ce n''est pas la même terminaison que « в университет ».","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":7}},{"type":"paragraph","text":"En français, on ajoute souvent des petits mots — à, de, avec, dans, pour — pour exprimer ces relations. Le russe fait souvent l''inverse : au lieu d''ajouter un mot, il modifie la fin du nom. La terminaison devient un indice du rôle du mot dans la phrase."},{"type":"callout","text":"Ce n''est pas une exception grammaticale. C''est une manière plus compacte d''exprimer les relations entre les mots. Dans Rossiyani, tu as d''abord rencontré ces formes en lisant — cette leçon te donne le cadre pour les comprendre."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 280\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">ÉCOLE</text><rect x=\"190\" y=\"44\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"67\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">школа</text><line x1=\"240\" y1=\"80\" x2=\"240\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"80\" y1=\"108\" x2=\"400\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"80\" y1=\"108\" x2=\"80\" y2=\"132\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"240\" y1=\"108\" x2=\"240\" y2=\"132\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"400\" y1=\"108\" x2=\"400\" y2=\"132\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"80\" y=\"152\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Sujet</text><text x=\"240\" y=\"152\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Destination</text><text x=\"400\" y=\"152\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Lieu</text><rect x=\"30\" y=\"164\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"80\" y=\"187\" text-anchor=\"middle\" font-size=\"15\" fill=\"#3B82F6\" font-family=\"serif\">школа</text><rect x=\"190\" y=\"164\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"240\" y=\"187\" text-anchor=\"middle\" font-size=\"15\" fill=\"#22C55E\" font-family=\"serif\">школу</text><rect x=\"350\" y=\"164\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"400\" y=\"187\" text-anchor=\"middle\" font-size=\"15\" fill=\"#22C55E\" font-family=\"serif\">школе</text></svg>","caption":"Le mot reste le même. La terminaison indique simplement son rôle."},{"type":"takeaways","items":["Les cas ne créent pas de nouveaux mots — ils changent la fonction d''un mot dans la phrase.","Une terminaison est un indice de rôle, pas une exception à mémoriser.","Tu as déjà vu ces changements dans tes textes Rossiyani avant de connaître le mot « cas ».","Comprendre le rôle est plus important que mémoriser le nom du cas.","Dans Rossiyani, on cherche toujours le pourquoi avant le nom de la règle."]}]'::jsonb,
  related_texts = '[{"textTitle":"Первый день в университете","goldNumber":1,"phenomenon":"même lieu, terminaisons différentes (в университет / в аудитории)","sentenceIndices":[4,6,7]},{"textTitle":"В булочной","goldNumber":2,"phenomenon":"terminaisons en contexte d''achat","sentenceIndices":[3,4]},{"textTitle":"Как найти дорогу?","goldNumber":9,"phenomenon":"directions et formes en mouvement","sentenceIndices":[4,5,6]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'les-cas-changent-le-role';

UPDATE lessons
SET
  title = 'Pourquoi le russe a des cas (et le français non) ?',
  content_blocks = '[{"type":"paragraph","text":"En français, c''est souvent l''ordre des mots qui indique leur rôle : « Le chat mange la souris » n''a pas le même sens que « La souris mange le chat ». En russe, le rôle d''un mot est porté par sa terminaison — c''est ce qu''on appelle un cas."},{"type":"example","russian":"Ко́шка ест мы́шку.","translation":"Le chat mange la souris.","words":[{"text":"Ко́шка","role":"subject"},{"text":"ест","role":null},{"text":"мы́шку","role":"object"}],"note":"« ко́шка » porte la terminaison du sujet, « мы́шку » celle de l''objet. C''est la terminaison — pas la position — qui dit qui mange qui."},{"type":"example","russian":"Мы́шку ест ко́шка.","translation":"Le chat mange la souris.","words":[{"text":"Мы́шку","role":"object"},{"text":"ест","role":null},{"text":"Ко́шка","role":"subject"}],"note":"Même sens exact, ordre inversé. En russe, on peut réorganiser une phrase sans en changer le sens, parce que les terminaisons portent l''information."},{"type":"paragraph","text":"Tu as déjà rencontré ce système en lisant. Quand Louis veut acheter du pain, le mot « хлеб » joue un rôle précis dans la phrase — pas celui du sujet."},{"type":"example","russian":"— Я хочу́ ку́пить хлеб.","translation":"Je veux acheter du pain.","words":[{"text":"Я","role":"subject"},{"text":"хочу́","role":null},{"text":"ку́пить","role":null},{"text":"хлеб","role":"object"}],"note":"Dans « В булочной », Louis est le sujet et le pain est ce qu''il veut acheter — un objet direct. Sa terminaison (ici identique au dictionnaire) indique ce rôle.","sourceText":{"textTitle":"В булочной","sentenceIndex":3}},{"type":"paragraph","text":"Quand il demande son chemin, les indications utilisent aussi des formes précises — « прямо », « направо », « слева » s''appuient sur le même principe : chaque mot a un rôle, et la terminaison l''exprime."},{"type":"callout","text":"Un cas, c''est une terminaison qui répond à la question « quel est le rôle de ce mot ici ? » — sujet, objet, lieu, destinataire, possession… Le russe en a six. Tu les as déjà croisés dans le Reader, à travers les couleurs fonctionnelles : bleu (sujet), corail (objet), vert (lieu), violet (possession), ambre (destinataire)."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 200\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">LES SIX CAS</text><rect x=\"20\" y=\"40\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"85\" y=\"61\" text-anchor=\"middle\" font-size=\"13\" fill=\"#3B82F6\" font-family=\"serif\">Nominatif</text><rect x=\"175\" y=\"40\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"240\" y=\"61\" text-anchor=\"middle\" font-size=\"13\" fill=\"#EF7C5A\" font-family=\"serif\">Accusatif</text><rect x=\"330\" y=\"40\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"395\" y=\"61\" text-anchor=\"middle\" font-size=\"13\" fill=\"#A78BFA\" font-family=\"serif\">Génitif</text><rect x=\"20\" y=\"88\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"85\" y=\"109\" text-anchor=\"middle\" font-size=\"13\" fill=\"#F59E0B\" font-family=\"serif\">Datif</text><rect x=\"175\" y=\"88\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"240\" y=\"109\" text-anchor=\"middle\" font-size=\"13\" fill=\"#5A5A5A\" font-family=\"serif\">Instrumental</text><rect x=\"330\" y=\"88\" width=\"130\" height=\"32\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"395\" y=\"109\" text-anchor=\"middle\" font-size=\"13\" fill=\"#22C55E\" font-family=\"serif\">Prépositionnel</text><line x1=\"240\" y1=\"128\" x2=\"240\" y2=\"148\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><rect x=\"155\" y=\"148\" width=\"170\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"171\" text-anchor=\"middle\" font-size=\"13\" fill=\"#0E0E0E\">Chaque terminaison = un rôle</text></svg>","caption":"Six cas, six questions sur le rôle d''un mot dans la phrase."},{"type":"takeaways","items":["En russe, la terminaison porte le rôle du mot — pas sa position dans la phrase.","Tu as déjà vu ces rôles en lisant, avant de connaître le mot « cas ».","Les couleurs du Reader correspondent aux cas : sujet, objet, lieu, possession, destinataire.","Ce parcours va te montrer, cas par cas, comment reconnaître ces terminaisons.","Comprendre le rôle vaut mieux que mémoriser une table de déclinaison."]}]'::jsonb,
  related_texts = '[{"textTitle":"Первый день в университете","goldNumber":1,"phenomenon":"mouvement et position (в + différentes terminaisons)","sentenceIndices":[4,6,7]},{"textTitle":"В булочной","goldNumber":2,"phenomenon":"objet direct (accusatif)","sentenceIndices":[3,4,5]},{"textTitle":"Как найти дорогу?","goldNumber":9,"phenomenon":"directions et mouvement","sentenceIndices":[0,4,5,6]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'pourquoi-les-cas';

UPDATE lessons
SET
  title = 'Comment reconnaître le sujet d''une phrase ?',
  content_blocks = '[{"type":"paragraph","text":"Le nominatif est le cas de base — celui du dictionnaire, celui qu''on apprend en premier. C''est aussi le cas du sujet : la personne ou la chose qui fait l''action. Dans Rossiyani, c''est le rôle que tu vois en bleu."},{"type":"example","russian":"Преподава́тель улыба́ется и говори́т:","translation":"Le professeur sourit et dit :","words":[{"text":"Преподава́тель","role":"subject"},{"text":"улыба́ется","role":null},{"text":"и","role":null},{"text":"говори́т","role":null}],"note":"Dans « Первый день в университете », « преподаватель » est au nominatif : c''est lui qui sourit et parle. C''est la forme que tu trouverais dans un dictionnaire.","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":8}},{"type":"example","russian":"Они́ вхо́дят в университе́т вме́сте.","translation":"Ils entrent ensemble dans l''université.","words":[{"text":"Они́","role":"subject"},{"text":"вхо́дят","role":null},{"text":"в","role":null},{"text":"университе́т","role":"place"}],"note":"« они » est le sujet — Anna et Louis ensemble. Le nominatif pluriel se termine souvent en -и ou -ы.","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":6}},{"type":"callout","text":"Repère utile : quand tu cherches un mot dans le panel Explorer, c''est toujours sa forme au nominatif qui s''affiche en gras — c''est la forme de référence pour tous les autres cas."},{"type":"example","russian":"— Да, я францу́з. А ты ру́сская?","translation":"Oui, je suis français. Et toi, tu es russe ?","words":[{"text":"я","role":"subject"},{"text":"францу́з","role":null},{"text":"ты","role":"subject"},{"text":"ру́сская","role":null}],"note":"Dans « Знакомство », Louis et Anna se présentent. « я » et « ты » sont les sujets — au nominatif, comme dans le dictionnaire.","sourceText":{"textTitle":"Знакомство","sentenceIndex":6}},{"type":"paragraph","text":"Le nominatif est ton point de départ. Les cinq cas suivants existent pour exprimer tout ce que le sujet n''exprime pas : ce qu''il fait subir, à qui, où, avec quoi, ou à qui appartient quoi."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 160\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">NOMINATIF</text><rect x=\"140\" y=\"40\" width=\"200\" height=\"40\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"65\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">форма словаря</text><line x1=\"240\" y1=\"80\" x2=\"240\" y2=\"100\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><rect x=\"155\" y=\"100\" width=\"170\" height=\"40\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"240\" y=\"125\" text-anchor=\"middle\" font-size=\"14\" fill=\"#3B82F6\" font-family=\"serif\">qui agit ?</text></svg>","caption":"Le nominatif répond à « qui ? » ou « quoi ? » — c''est celui qui agit."},{"type":"takeaways","items":["Le nominatif est la forme du dictionnaire et le cas du sujet.","Dans le Reader, le sujet apparaît en bleu.","Tu l''as déjà vu dans tes textes : преподаватель, они, я, ты…","Tous les autres cas expriment des rôles différents du sujet.","Cherche toujours « qui fait l''action ? » pour repérer le nominatif."]}]'::jsonb,
  related_texts = '[{"textTitle":"Первый день в университете","goldNumber":1,"phenomenon":"sujets : преподаватель, они","sentenceIndices":[6,8,9]},{"textTitle":"Знакомство","goldNumber":5,"phenomenon":"sujets implicites dans les présentations","sentenceIndices":[1,5,6]},{"textTitle":"Обычный день студента","goldNumber":10,"phenomenon":"routine — sujets Луи, они","sentenceIndices":[0,2,4]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'nominatif';

UPDATE lessons
SET
  title = 'Pourquoi certains mots changent quand on les « subit » ?',
  content_blocks = '[{"type":"paragraph","text":"L''accusatif marque ce qui reçoit directement l''action — la chose ou la personne qu''on achète, qu''on lit, qu''on mange. C''est le rôle que tu vois en corail dans Rossiyani. Tu l''as rencontré dès « В булочной »."},{"type":"example","russian":"— Я хочу́ ку́пить хлеб.","translation":"Je veux acheter du pain.","words":[{"text":"Я","role":"subject"},{"text":"хочу́","role":null},{"text":"ку́пить","role":null},{"text":"хлеб","role":"object"}],"note":"Louis est le sujet. Le pain est ce qu''il veut acheter — l''objet direct. Pour « хлеб » (masculin inanimé), la forme à l''accusatif est identique au nominatif.","sourceText":{"textTitle":"В булочной","sentenceIndex":3}},{"type":"example","russian":"— Нет, ещё молоко́.","translation":"Non, aussi du lait.","words":[{"text":"ещё","role":null},{"text":"молоко́","role":"object"}],"note":"« молоко » (neutre) reste identique à l''accusatif. L''objet direct ne change pas toujours de terminaison — c''est surtout visible sur les mots féminins en -а.","sourceText":{"textTitle":"В булочной","sentenceIndex":5}},{"type":"example","russian":"— Вот ваш хлеб и молоко́.","translation":"Voici votre pain et votre lait.","words":[{"text":"хлеб","role":"object"},{"text":"молоко́","role":"object"}],"note":"Le vendeur remet ce qui a été acheté — pain et lait sont toujours des objets directs.","sourceText":{"textTitle":"В булочной","sentenceIndex":7}},{"type":"comparison","title":"Nominatif → Accusatif (féminin en -а)","columns":["Nominatif","Accusatif","Sens"],"rows":[{"label":"кни́га","values":["кни́гу","livre"]},{"label":"рабо́та","values":["рабо́ту","travail"]},{"label":"хлеб","values":["хлеб","pain (inanimé — pas de changement)"]}]},{"type":"callout","text":"Astuce : pour les mots masculins inanimés et les mots neutres, l''accusatif est souvent identique au nominatif. C''est pour ça que « хлеб » ne change pas — mais le rôle (objet direct) est bien là, et le Reader le colore en corail quand tu explores."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 280\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">ACHETER</text><rect x=\"190\" y=\"44\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"67\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">купить</text><line x1=\"120\" y1=\"80\" x2=\"120\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"360\" y1=\"80\" x2=\"360\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"120\" y1=\"80\" x2=\"360\" y2=\"80\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"120\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Sujet</text><text x=\"360\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Objet direct</text><rect x=\"70\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"120\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#3B82F6\" font-family=\"serif\">я</text><rect x=\"310\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"360\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#EF7C5A\" font-family=\"serif\">хлеб</text><text x=\"240\" y=\"210\" text-anchor=\"middle\" font-size=\"12\" fill=\"#5A5A5A\">qui achète → quoi est acheté</text></svg>","caption":"Le nominatif dit qui agit, l''accusatif dit sur quoi ou sur qui porte l''action."},{"type":"takeaways","items":["L''accusatif = objet direct — ce qui « subit » l''action (acheter, lire, manger…).","Tu l''as vu dans « В булочной » : купить хлеб, ещё молоко.","Les féminins en -а changent souvent (-а → -у) ; les masculins inanimés souvent pas.","Dans le Reader, l''objet direct apparaît en corail.","Demande-toi « quoi ? » ou « qui ? » après le verbe pour repérer l''accusatif."]}]'::jsonb,
  related_texts = '[{"textTitle":"В булочной","goldNumber":2,"phenomenon":"accusatif objet direct (купить хлеб, молоко)","sentenceIndices":[3,4,5,7]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'accusatif';

UPDATE lessons
SET
  title = 'Comment exprimer « de » ou « à qui appartient » ?',
  content_blocks = '[{"type":"paragraph","text":"Le génitif répond d''abord à la question « de qui ? » ou « de quoi ? » — c''est le cas de la possession. C''est le rôle que tu vois en violet dans Rossiyani."},{"type":"example","russian":"Э́то маши́на бра́та.","translation":"C''est la voiture du frère.","words":[{"text":"Э́то","role":null},{"text":"маши́на","role":null},{"text":"бра́та","role":"possession"}],"note":"« брат » (frère, nominatif) devient « бра́та » au génitif : c''est la voiture qui appartient à lui. En français, on ajoute « du » ; en russe, c''est la terminaison qui porte cette idée."},{"type":"example","russian":"Э́то кни́га сестры́.","translation":"C''est le livre de la sœur.","words":[{"text":"Э́то","role":null},{"text":"кни́га","role":null},{"text":"сестры́","role":"possession"}],"note":"« сестра́ » devient « сестры́ » : la terminaison -а devient -ы. Chaque genre a sa propre transformation, mais l''idée reste la même."},{"type":"paragraph","text":"Tu as déjà croisé une construction proche dans « У врача ». Quand Louis dit qu''il a mal, il utilise « у меня » — une expression où le génitif interviendra plus tard dans d''autres contextes."},{"type":"example","russian":"— У меня́ боли́т го́рло и немно́го боли́т голова́.","translation":"J''ai mal à la gorge et un peu mal à la tête.","words":[{"text":"У","role":null},{"text":"меня́","role":"possession"},{"text":"боли́т","role":null},{"text":"го́рло","role":null}],"note":"« у меня » exprime une relation de possession ou d''état — « chez moi / à moi ». Rossiyani te le signale en violet ici pour t''habituer à repérer ces constructions avant d''aller plus loin.","sourceText":{"textTitle":"У врача","sentenceIndex":6}},{"type":"callout","text":"Le génitif ne sert pas qu''à la possession : il apparaît aussi après des quantités (« beaucoup de »), certaines prépositions (« sans », « près de »), et pour nier l''existence. Rossiyani te le signale en violet quand son rôle est la possession — les autres usages viendront dans des leçons dédiées."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 280\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">POSSESSION</text><rect x=\"190\" y=\"44\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"67\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">машина</text><line x1=\"240\" y1=\"80\" x2=\"240\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"120\" y1=\"108\" x2=\"360\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"120\" y1=\"108\" x2=\"120\" y2=\"132\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"360\" y1=\"108\" x2=\"360\" y2=\"132\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"120\" y=\"152\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Nominatif</text><text x=\"360\" y=\"152\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Génitif</text><rect x=\"70\" y=\"164\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"120\" y=\"187\" text-anchor=\"middle\" font-size=\"15\" fill=\"#3B82F6\" font-family=\"serif\">брат</text><rect x=\"310\" y=\"164\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"360\" y=\"187\" text-anchor=\"middle\" font-size=\"15\" fill=\"#A78BFA\" font-family=\"serif\">брата</text><text x=\"240\" y=\"230\" text-anchor=\"middle\" font-size=\"12\" fill=\"#5A5A5A\">la voiture de qui ? → du frère</text></svg>","caption":"Le génitif indique à qui appartient la chose dont on parle."},{"type":"takeaways","items":["Le génitif répond à « de qui ? » / « de quoi ? » — la possession.","En français on ajoute « de » ; en russe, la terminaison change.","Tu as vu « у меня » dans « У врача » — une construction liée à ce cas.","Dans le Reader, la possession apparaît en violet.","Demande-toi « à qui appartient ça ? » pour repérer le génitif."]}]'::jsonb,
  related_texts = '[{"textTitle":"У врача","goldNumber":8,"phenomenon":"expressions avec у (у меня, у него) — semis pour usages futurs du génitif","sentenceIndices":[1,6]},{"textTitle":"Обычный день студента","goldNumber":10,"phenomenon":"русского языка (génitif dans les noms composés)","sentenceIndices":[4,8]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'genitif';

UPDATE lessons
SET
  title = 'Comment dire « à quelqu''un » en russe ?',
  content_blocks = '[{"type":"paragraph","text":"Le datif marque à qui une chose est donnée, dite ou destinée. C''est le rôle que tu vois en ambre dans Rossiyani — souvent après des verbes comme « donner », « dire », « écrire », « montrer »."},{"type":"example","russian":"— Мне то́же.","translation":"Moi aussi.","words":[{"text":"Мне","role":"recipient"},{"text":"то́же","role":null}],"note":"Dans « Знакомство », après « Очень приятно », Louis répond « Мне тоже ». « мне » est au datif — c''est à lui que s''adresse le sentiment, comme en français « à moi aussi ».","sourceText":{"textTitle":"Знакомство","sentenceIndex":4}},{"type":"example","russian":"— Вам ну́жно отдыха́ть и пить больше воды́.","translation":"Vous devez vous reposer et boire plus d''eau.","words":[{"text":"Вам","role":"recipient"},{"text":"ну́жно","role":null},{"text":"отдыха́ть","role":null}],"note":"Dans « У врача », le médecin s''adresse à Louis avec « вам » — la forme de politesse au datif. C''est à lui que la recommandation est destinée.","sourceText":{"textTitle":"У врача","sentenceIndex":9}},{"type":"example","russian":"Оте́ц даёт де́ньги сы́ну.","translation":"Le père donne de l''argent à son fils.","words":[{"text":"Оте́ц","role":"subject"},{"text":"даёт","role":null},{"text":"де́ньги","role":"object"},{"text":"сы́ну","role":"recipient"}],"note":"« сын » devient « сы́ну » au datif. L''argent est ce qui est donné (accusatif) ; le fils est celui à qui (datif) — deux rôles, deux cas, dans la même phrase."},{"type":"callout","text":"Repère utile : si tu peux reformuler en français avec « à » devant une personne (« à moi », « à son fils », « à vous »), c''est très probablement un datif en russe."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 280\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">DONNER</text><rect x=\"190\" y=\"44\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"67\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">даёт</text><line x1=\"120\" y1=\"80\" x2=\"120\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"360\" y1=\"80\" x2=\"360\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"120\" y1=\"80\" x2=\"360\" y2=\"80\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"120\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Objet (quoi ?)</text><text x=\"360\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Destinataire (à qui ?)</text><rect x=\"70\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"120\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#EF7C5A\" font-family=\"serif\">деньги</text><rect x=\"310\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"360\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#F59E0B\" font-family=\"serif\">сыну</text></svg>","caption":"Le datif répond à « à qui ? » — le destinataire de l''action."},{"type":"takeaways","items":["Le datif = destinataire — « à qui ? » quelque chose est dit, donné ou destiné.","Tu l''as vu dans « Знакомство » (мне) et « У врача » (вам).","Dans le Reader, le destinataire apparaît en ambre.","Une même phrase peut avoir un accusatif (quoi) et un datif (à qui).","Teste avec « à + personne » en français pour repérer le datif."]}]'::jsonb,
  related_texts = '[{"textTitle":"Знакомство","goldNumber":5,"phenomenon":"мне (datif)","sentenceIndices":[4]},{"textTitle":"У врача","goldNumber":8,"phenomenon":"вам (datif poli)","sentenceIndices":[9]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'datif';

UPDATE lessons
SET
  title = 'Comment dire « avec » en russe ?',
  content_blocks = '[{"type":"paragraph","text":"L''instrumental répond à la question « avec quoi ? » ou « avec qui ? ». Il exprime l''outil utilisé pour faire une action, ou la personne qui accompagne quelqu''un."},{"type":"example","russian":"Луи́ платит ка́ртой.","translation":"Louis paie par carte.","words":[{"text":"Луи́","role":"subject"},{"text":"платит","role":null},{"text":"ка́ртой","role":null}],"note":"Dans « В булочной », Louis paie avec sa carte. « карта » devient « картой » à l''instrumental — c''est l''outil du paiement. La terminaison -ой est typique du féminin à ce cas.","sourceText":{"textTitle":"В булочной","sentenceIndex":8}},{"type":"example","russian":"Вме́сте они́ иду́т на уро́к ру́сского языка́.","translation":"Ensemble, ils vont au cours de russe.","words":[{"text":"Вме́сте","role":null},{"text":"они́","role":"subject"},{"text":"иду́т","role":null}],"note":"Dans « Обычный день студента », Anna et Louis vont ensemble au cours. « вместе » exprime la compagnie — l''autre grand usage de l''instrumental, souvent avec la préposition « с ».","sourceText":{"textTitle":"Обычный день студента","sentenceIndex":4}},{"type":"example","russian":"Он идёт в кино́ с сестро́й.","translation":"Il va au cinéma avec sa sœur.","words":[{"text":"Он","role":"subject"},{"text":"идёт","role":null},{"text":"с","role":null},{"text":"сестро́й","role":null}],"note":"« сестра » devient « сестрой » après « с » (avec) : c''est le sens de compagnie — aller quelque part avec quelqu''un."},{"type":"callout","text":"L''instrumental n''a pas encore de couleur dédiée dans le Reader — les cinq couleurs actuelles couvrent sujet, objet, lieu, possession et destinataire. Rossiyani préfère ne pas improviser une couleur plutôt que d''en choisir une incohérente."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 280\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">INSTRUMENTAL</text><rect x=\"190\" y=\"44\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"67\" text-anchor=\"middle\" font-size=\"15\" fill=\"#0E0E0E\" font-family=\"serif\">платит</text><line x1=\"120\" y1=\"80\" x2=\"120\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"360\" y1=\"80\" x2=\"360\" y2=\"108\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><line x1=\"120\" y1=\"80\" x2=\"360\" y2=\"80\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"120\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Sujet</text><text x=\"360\" y=\"128\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#5A5A5A\">Avec quoi ?</text><rect x=\"70\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"120\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#3B82F6\" font-family=\"serif\">Луи</text><rect x=\"310\" y=\"140\" width=\"100\" height=\"36\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"360\" y=\"163\" text-anchor=\"middle\" font-size=\"15\" fill=\"#5A5A5A\" font-family=\"serif\">картой</text><text x=\"240\" y=\"210\" text-anchor=\"middle\" font-size=\"12\" fill=\"#5A5A5A\">moyen ou compagnie</text></svg>","caption":"L''instrumental indique avec quoi ou avec qui l''action se fait."},{"type":"takeaways","items":["L''instrumental = « avec quoi ? » (outil) ou « avec qui ? » (compagnie).","Tu l''as vu dans « В булочной » : платит картой.","Après « с » (avec), un nom de personne prend souvent l''instrumental.","Pas encore de couleur Reader dédiée — repère la terminaison -ой, -ом, -ей…","Teste avec « avec + chose/personne » en français."]}]'::jsonb,
  related_texts = '[{"textTitle":"В булочной","goldNumber":2,"phenomenon":"instrumental moyen (платит картой)","sentenceIndices":[8]},{"textTitle":"Обычный день студента","goldNumber":10,"phenomenon":"вместе (compagnie implicite)","sentenceIndices":[4,5]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'instrumental';

UPDATE lessons
SET
  title = 'Pourquoi в университет mais в аудитории ?',
  content_blocks = '[{"type":"paragraph","text":"Le prépositionnel s''utilise toujours après une préposition — jamais seul. Il exprime le lieu où l''on se trouve (pas où l''on va) ou le sujet dont on parle. C''est le rôle que tu vois en vert dans Rossiyani quand il indique un lieu."},{"type":"example","russian":"В аудито́рии уже́ есть студе́нты.","translation":"Dans la salle, il y a déjà des étudiants.","words":[{"text":"В","role":null},{"text":"аудито́рии","role":"place"},{"text":"студе́нты","role":"subject"}],"note":"Dans « Первый день в университете », les étudiants sont déjà dans la salle — pas de mouvement. « в аудитории » utilise le prépositionnel : on est à l''intérieur.","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":7}},{"type":"example","russian":"— Ты идёшь в университе́т?","translation":"Tu vas à l''université ?","words":[{"text":"Ты","role":"subject"},{"text":"идёшь","role":null},{"text":"в","role":null},{"text":"университе́т","role":"place"}],"note":"Quelques phrases avant, « в университет » marquait une direction — un mouvement vers l''université. Même préposition « в », mais terminaison différente selon qu''on va vers ou qu''on est déjà dedans.","sourceText":{"textTitle":"Первый день в университете","sentenceIndex":4}},{"type":"example","russian":"А́нна уже́ ждёт его́ внутри́.","translation":"Anna l''attend déjà à l''intérieur.","words":[{"text":"А́нна","role":"subject"},{"text":"ждёт","role":null},{"text":"внутри́","role":"place"}],"note":"Dans « Как найти дорогу? », Anna attend Louis à l''intérieur de la bibliothèque — une position fixe, pas un déplacement.","sourceText":{"textTitle":"Как найти дорогу?","sentenceIndex":10}},{"type":"comparison","title":"Direction vs position avec « в »","columns":["Situation","Cas","Exemple"],"rows":[{"label":"Mouvement vers","values":["Accusatif","в университет"]},{"label":"Position dans","values":["Prépositionnel","в аудитории"]}]},{"type":"callout","text":"Le piège classique : « в » (et « на ») peut demander soit l''accusatif (direction) soit le prépositionnel (position). La différence ne se voit pas sur la préposition, mais sur la terminaison du mot qui suit — exactement ce que tu as vécu en lisant le premier jour à l''université."},{"type":"schema","svgContent":"<svg viewBox=\"0 0 480 160\" xmlns=\"http://www.w3.org/2000/svg\"><text x=\"240\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#0E0E0E\">в + lieu</text><rect x=\"30\" y=\"44\" width=\"190\" height=\"48\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"125\" y=\"66\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#EF7C5A\">Accusatif</text><text x=\"125\" y=\"84\" text-anchor=\"middle\" font-size=\"14\" fill=\"#0E0E0E\" font-family=\"serif\">в университет → vers</text><line x1=\"240\" y1=\"68\" x2=\"240\" y2=\"68\" stroke=\"#4F46E5\" stroke-width=\"2\"/><rect x=\"260\" y=\"44\" width=\"190\" height=\"48\" rx=\"8\" fill=\"#FFFFFF\" stroke=\"#E8E4DC\" stroke-width=\"1.5\"/><text x=\"355\" y=\"66\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#22C55E\">Prépositionnel</text><text x=\"355\" y=\"84\" text-anchor=\"middle\" font-size=\"14\" fill=\"#0E0E0E\" font-family=\"serif\">в аудитории → dans</text><line x1=\"240\" y1=\"100\" x2=\"240\" y2=\"120\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><rect x=\"155\" y=\"120\" width=\"170\" height=\"32\" rx=\"8\" fill=\"#EEF0FF\" stroke=\"#4F46E5\" stroke-width=\"1.5\"/><text x=\"240\" y=\"141\" text-anchor=\"middle\" font-size=\"12\" fill=\"#0E0E0E\">même préposition, terminaison différente</text></svg>","caption":"Direction (vers) et position (dans) — la terminaison tranche."},{"type":"takeaways","items":["Le prépositionnel = lieu où l''on est déjà, ou sujet de conversation (о…).","Tu l''as vécu dans « Первый день » : в университет (vers) vs в аудитории (dans).","« в » et « на » changent de cas selon mouvement ou position.","Dans le Reader, le lieu apparaît en vert.","Demande-toi : « est-ce qu''on va vers, ou est-ce qu''on y est déjà ? »"]}]'::jsonb,
  related_texts = '[{"textTitle":"Первый день в университете","goldNumber":1,"phenomenon":"в университет (direction) vs в аудитории (position)","sentenceIndices":[4,6,7]},{"textTitle":"Как найти дорогу?","goldNumber":9,"phenomenon":"lieu et position (внутри, слева)","sentenceIndices":[6,10]}]'::jsonb,
  updated_at = now()
FROM lesson_paths lp
WHERE lessons.path_id = lp.id
  AND lp.slug = 'les-six-cas'
  AND lessons.slug = 'prepositionnel';

